import json

# Get the business data from storage
businesses = locals()['var_functions.query_db:30']

# Process businesses to find those accepting credit cards and extract categories
credit_card_businesses = []
category_info = {}  # category -> {count: int, business_ids: list}

for business in businesses:
    attributes = business.get('attributes')
    if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
        business_id = business['business_id']
        description = business.get('description', '')

        # Extract categories from description
        categories = []
        if 'services in' in description:
            parts = description.split('services in')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.')
                categories = [cat.strip() for cat in category_text.split(',')]
        elif 'services including' in description:
            parts = description.split('services including')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.')
                categories = [cat.strip() for cat in category_text.split(',')]
        elif 'category of' in description:
            parts = description.split('category of')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.').strip("'")
                categories = [cat.strip() for cat in category_text.split(',')]

        # Clean categories - remove 'and' prefix and handle 'and' in middle
        cleaned_categories = []
        for category in categories:
            if category:
                # Handle categories like "and Montessori Schools"
                if category.startswith('and '):
                    cleaned_categories.append(category[4:].strip())
                # Handle categories with "and" in the middle like "Hair Salons and Beauty & Spas"
                elif ' and ' in category and len(categories) == 1:
                    # Only split if it's a single category containing 'and'
                    split_cats = [cat.strip() for cat in category.split(' and ')]
                    cleaned_categories.extend(split_cats)
                else:
                    cleaned_categories.append(category)

        credit_card_businesses.append({
            'business_id': business_id,
            'name': business['name'],
            'categories': cleaned_categories
        })

        # Update category counts
        for category in cleaned_categories:
            if category:
                if category not in category_info:
                    category_info[category] = {'count': 0, 'business_ids': []}
                category_info[category]['count'] += 1
                category_info[category]['business_ids'].append(business_id)

# Find the category with the most businesses
most_common_category = None
most_common_count = 0
businesses_in_top_category = []

if category_info:
    most_common_category = max(category_info.keys(), key=lambda x: category_info[x]['count'])
    most_common_count = category_info[most_common_category]['count']
    businesses_in_top_category = category_info[most_common_category]['business_ids']

print('__RESULT__:')
print(json.dumps({
    'total_credit_card_businesses': len(credit_card_businesses),
    'most_common_category': most_common_category,
    'most_common_count': most_common_count,
    'businesses_in_top_category': businesses_in_top_category,
    'all_categories': dict(sorted([(k, v['count']) for k, v in category_info.items()], key=lambda x: x[1], reverse=True))
}))

